1	import {
2		formatSpawnFailure,
3		inspectDockerContainer,
4		runDockerStatus,
5		spawnOutput,
6	} from "../docker/client.js";
7	import {
8		addCheck,
9		addFailedCheck,
10	} from "../reports/format.js";
11	import type {
12		DevServicesReport,
13		PostgresReport,
14	} from "../reports/types.js";
15	import type { DevPostgresConfig } from "./config.js";
16	
17	export function checkPostgresDoctor(
18		report: DevServicesReport,
19		target: PostgresReport,
20		config: DevPostgresConfig,
21		dockerAvailable: boolean,
22		postgresTable?: string,
23	): void {
24		if (!dockerAvailable) {
25			addFailedCheck(report, target, {
26				name: "postgres-container",
27				message: "Skipped Postgres checks because Docker is not available.",
28				remediation: "Start Docker, then run pnpm dev:setup.",
29			});
30			addSkippedPostgresChecks(target, postgresTable, "Docker is not available.");
31			return;
32		}
33	
34		const state = inspectDockerContainer(config.containerName);
35		if (state !== "running") {
36			addFailedCheck(report, target, {
37				name: "postgres-container",
38				message: `${config.containerName} is ${state}.`,
39				remediation: "Run pnpm dev:setup.",
40			});
41			addSkippedPostgresChecks(target, postgresTable, "Postgres container is not running.");
42			return;
43		}
44	
45		addCheck(target, {
46			name: "postgres-container",
47			status: "pass",
48			message: `${config.containerName} is running.`,
49		});
50	
51		if (!checkPostgresReady(report, target, config)) {
52			addSkippedPostgresChecks(target, postgresTable, "Postgres is not accepting connections.");
53			return;
54		}
55	
56		if (!checkPostgresDatabase(report, target, config)) {
57			if (postgresTable) {
58				addCheck(target, {
59					name: `postgres-table:${postgresTable}`,
60					status: "skip",
61					message: "Database does not exist.",
62				});
63			}
64			return;
65		}
66	
67		if (postgresTable) {
68			checkPostgresTable(report, target, config, postgresTable);
69		}
70	}
71	
72	function checkPostgresReady(
73		report: DevServicesReport,
74		target: PostgresReport,
75		config: DevPostgresConfig,
76	): boolean {
77		const result = runDockerStatus([
78			"exec",
79			config.containerName,
80			"pg_isready",
81			"-U",
82			config.username,
83			"-d",
84			"postgres",
85		]);
86	
87		if (result.status === 0) {
88			addCheck(target, {
89				name: "postgres-ready",
90				status: "pass",
91				message: "Postgres accepts connections.",
92			});
93			return true;
94		}
95	
96		addFailedCheck(report, target, {
97			name: "postgres-ready",
98			message: `Postgres is not ready. ${formatSpawnFailure(result)}`,
99			remediation: "Run pnpm dev:setup.",
100		});
101		return false;
102	}
103	
104	function checkPostgresDatabase(
105		report: DevServicesReport,
106		target: PostgresReport,
107		config: DevPostgresConfig,
108	): boolean {
109		const result = runDockerStatus([
110			"exec",
111			config.containerName,
112			"psql",
113			"-U",
