	assert.equal(
		assertLocalDevPostgresUrl("postgresql://postgres:postgres@127.0.0.1:5432/worktree_db").databaseName,
		"worktree_db",
	);
	assert.throws(
		() => assertLocalDevPostgresUrl("postgresql://postgres:postgres@example.com:5432/worktree_db"),
